arguments.argument:
if global.gamePaused=false
{
  if sprite_index=sWepPickupArrows
  {
    yVel+=0.2
    if yVel>yVelLimit
      yVel=yVelLimit
  }
  else if sprite_index=sCVHeart
  {
    yVel+=0.01
    if yVel>yVelLimit
      yVel=yVelLimit
  }
  
  if sprite_index!=sMetroidMissile
  {
    if isCollisionBottom(1)
    {
      xVel=0
      yVel=0
    }
    else
    {
      if sprite_index=sCVHeart
        xVel=sin(oGame.time/6)
    }
    if isCollisionSolid()
      y-=2
    
    moveTo(xVel,yVel)
    if y>room_height+8
      instance_destroy()
  }
}
